var minimumPerimeter = function(neededApples) {
    const need = BigInt(neededApples);
    let lo = 1n, hi = 100000n;
    while (lo < hi) {
        const mid = (lo + hi) / 2n;
        if (2n * mid * (mid + 1n) * (2n * mid + 1n) >= need) hi = mid;
        else lo = mid + 1n;
    }
    return Number(8n * lo);
};
